+        assert_eq!(envelope["data"]["tx_id"], "tx:test");
+        assert_eq!(envelope["data"]["plan_id"], "plan:test");
+        assert_eq!(envelope["data"]["lifecycle_state"], "planned");
+        assert_eq!(envelope["data"]["receipt_count"], 0);
